INSERT INTO artists (id, name, bio) VALUES
  ('00000000-0000-0000-0000-000000000001', 'Maija Tabaka',    'Maija Tabaka (born 1939) is one of Latvia''s most celebrated painters, known for her expressive figurative works that blend symbolism with bold colour. Her paintings explore themes of femininity, identity, and the human condition, rendered in a distinctive style drawing from both Western modernism and Latvian folk tradition.'),
  ('00000000-0000-0000-0000-000000000002', 'Vija Celmiņš',    'Vija Celmiņš (born 1938, Riga) is a Latvian-American artist renowned for meticulous graphite and oil renderings of natural phenomena — ocean surfaces, star fields, desert floors. Her work is held in major collections including MoMA, the Tate, and the Whitney Museum.'),
  ('00000000-0000-0000-0000-000000000003', 'Kristaps Ģelzis', 'Kristaps Ģelzis (born 1962) is a Latvian painter and professor whose works move between figuration and abstraction. His large-format canvases depict dreamlike interiors and psychological landscapes rendered with layered, atmospheric colour.'),
  ('00000000-0000-0000-0000-000000000004', 'Arnis Balčus',    'Arnis Balčus (born 1978) is a Latvian photographer and editor-in-chief of FK Magazine. His photographic practice spans portraiture, documentary, and staged photography, examining post-Soviet identity, masculinity, and social ritual.'),
  ('00000000-0000-0000-0000-000000000005', 'Ieva Baklāne',    'Ieva Baklāne is a Latvian contemporary artist working primarily with sculpture, installation, and textile. Her works involve repetition, accumulation, and transformation of everyday materials into contemplative objects.'),
  ('00000000-0000-0000-0000-000000000006', 'Andris Eglītis',  'Andris Eglītis is a Latvian painter known for richly textured abstract works. Drawing from landscape and interior, his canvases balance spontaneity with structured composition, earning recognition across Baltic and European exhibitions.')
INSERT INTO artworks (id, title, artist_id, year, size, technique, price, description, image_url) VALUES
  ('00000000-0000-0000-0001-000000000001', 'Sieviete sarkanā',     '00000000-0000-0000-0000-000000000001', 2019, '120 × 90 cm',         'Oil on canvas',                       8500,  'A commanding figure study in deep reds and warm ochres. The subject gazes past the viewer with quiet authority, rendered in Tabaka''s characteristic gestural brushwork.',                                                   'https://picsum.photos/seed/artwork1/600/780'),
  ('00000000-0000-0000-0001-000000000002', 'Zilā silueta',          '00000000-0000-0000-0000-000000000001', 2021, '80 × 100 cm',          'Oil on canvas',                       6200,  'An abstracted female form dissolves into a field of deep cobalt and ultramarine, the figure''s edges softening into pure colour.',                                                                                             'https://picsum.photos/seed/artwork2/600/720'),
  ('00000000-0000-0000-0001-000000000003', 'Ocean Surface Study #7','00000000-0000-0000-0000-000000000002', 2018, '45 × 60 cm',           'Graphite on paper',                   14000, 'One of a series of intensely observed ocean surfaces, each wave recorded with painstaking precision. The graphite hatching creates a shimmering, near-photographic quality.',                                                   'https://picsum.photos/seed/artwork3/600/450'),
  ('00000000-0000-0000-0001-000000000004', 'Galaxy Field III',      '00000000-0000-0000-0000-000000000002', 2020, '50 × 50 cm',           'Oil on linen',                        18500, 'Stars rendered with obsessive care, each point of light built up from dozens of layers of oil paint. The deep black ground is achieved through multiple transparent glazes.',                                                  'https://picsum.photos/seed/artwork4/600/600'),
  ('00000000-0000-0000-0001-000000000005', 'Rozā jumti',            '00000000-0000-0000-0000-000000000003', 2022, '150 × 200 cm',         'Acrylic on canvas',                   11000, 'A panoramic cityscape dissolves into fields of rose and violet. Rooftops emerge and recede in a luminous haze, the architecture both specific and dreamlike.',                                                                  'https://picsum.photos/seed/artwork5/800/600'),
  ('00000000-0000-0000-0001-000000000006', 'Dzeltenā telpa',        '00000000-0000-0000-0000-000000000003', 2023, '100 × 120 cm',         'Oil and acrylic on canvas',           9800,  'An interior bathed in golden afternoon light. The painting collapses the boundary between room and memory, between observation and invention.',                                                                                  'https://picsum.photos/seed/artwork6/600/720'),
  ('00000000-0000-0000-0001-000000000007', 'Baznīcas svētki',       '00000000-0000-0000-0000-000000000004', 2021, '60 × 90 cm',           'C-print, edition of 5',               3200,  'From the series ''Latvian Rituals''. A parish festival photographed with intimate distance — the festive and the melancholic held in equal tension.',                                                                           'https://picsum.photos/seed/artwork7/900/600'),
  ('00000000-0000-0000-0001-000000000008', 'Portrets #12',          '00000000-0000-0000-0000-000000000004', 2022, '40 × 50 cm',           'Archival pigment print, edition of 3', 2400,  'A direct, unguarded portrait from the ongoing ''Faces'' series. The subject''s gaze creates an immediate, uncomfortable intimacy.',                                                                                            'https://picsum.photos/seed/artwork8/500/625'),
  ('00000000-0000-0000-0001-000000000009', 'Acumura I',             '00000000-0000-0000-0000-000000000005', 2023, 'Dimensions variable',  'Handwoven wool, steel armature',      5600,  'Wound threads accumulate into a dense, nest-like form. The work speaks to labour, patience, and the act of slow making as a counter to contemporary speed.',                                                                     'https://picsum.photos/seed/artwork9/600/800'),
  ('00000000-0000-0000-0001-000000000010', 'Atgriešanās',           '00000000-0000-0000-0000-000000000005', 2022, '30 × 40 × 20 cm',      'Ceramic, thread',                     2800,  'A ceramic vessel partially unravelled into thread — the object mid-transformation, returning to its material origins.',                                                                                                          'https://picsum.photos/seed/artwork10/600/500'),
  ('00000000-0000-0000-0001-000000000011', 'Laukums',               '00000000-0000-0000-0000-000000000006', 2020, '140 × 160 cm',         'Oil on canvas',                       7400,  'An abstracted field or plaza — the ground plane tilted up into a sea of layered textures. Raw umber and sage push against each other in compressed space.',                                                                       'https://picsum.photos/seed/artwork11/800/900'),
  ('00000000-0000-0000-0001-000000000012', 'Vakara ainava',         '00000000-0000-0000-0000-000000000006', 2023, '90 × 110 cm',          'Oil on canvas',                       6900,  'An evening landscape reduced to its essential light: the last glow on the horizon rendered in transparent glazes of amber and deep violet.',                                                                                      'https://picsum.photos/seed/artwork12/700/850')
